const data = $input.first().json.output;
const monthlyIncome = Number($('Preparar datos1').first().json['Ingreso-mensual']);
const userId = $('Preparar datos1').first().json.userId;

// El LLM devuelve "budget" y "alert_threshold" como PORCENTAJES (0-100),
// nunca euros. Todo el cálculo de dinero real se hace aquí, no en el LLM.
let categories = data.categories.map(cat => ({
  name: String(cat.name ?? 'Otros'),
  emoji: String(cat.emoji ?? '📦'),
  budgetPct: Math.max(0, Number(cat.budget) || 0),
  alertPct: Math.min(100, Math.max(0, Number(cat.alert_threshold) || 0)),
}));

const totalPct = categories.reduce((sum, c) => sum + c.budgetPct, 0);
const MAX_TOTAL_PCT = 90; // misma regla que el prompt: nunca más del 90% del ingreso

// Red de seguridad: pase lo que pase en el LLM, nunca se supera el 90% del ingreso.
const scale = totalPct > MAX_TOTAL_PCT ? MAX_TOTAL_PCT / totalPct : 1;

const finalCategories = categories.map(cat => {
  const budget = Math.round(monthlyIncome * (cat.budgetPct * scale) / 100);
  const alert_threshold = Math.round(budget * (cat.alertPct / 100));
  return { userId, name: cat.name, emoji: cat.emoji, budget, alert_threshold };
});

return [{ json: { categories: finalCategories } }];

